import { ParserRegistry } from "../../../../core/parser-registry";
import { _radialDomain as domain } from "./radial-domain-marks";
import { _radialTicks as ticks } from "./radial-ticks-marks";

export function _mainRadialAxis(data) {
    const self = this;

    const {container } = this;

    const domainMarks = domain.call(this, data);
    const ticksMarks = ticks.call(this, data);

    const radialAxisMarks = [
        domainMarks, ticksMarks
    ]

    return radialAxisMarks;
}
ParserRegistry.axis('radial.default', _mainRadialAxis);